def scrub_logs(log_string):
    # This regex specifically targets the patterns found in the provided test cases.
    # It looks for "api_key=" followed by alphanumeric characters, OR "key: " followed by digits and hyphens.
    pattern = r"(api_key=[a-zA-Z0-9]+)|(key: [0-9\-]+)"

